DELETE FROM youtube_comment_analysis_sentiment_items
WHERE history_id = #{historyId}
  AND (#{userId} IS NULL OR user_id = #{userId})

mapper.select:
SELECT COUNT(*)
FROM youtube_comment_analysis_sentiment_items
WHERE history_id = #{historyId}
  AND (#{userId} IS NULL OR user_id = #{userId})

    AND lex_label = #{label}


    AND (
      comment_id LIKE CONCAT('%', #{q}, '%')
      OR text_clean LIKE CONCAT('%', #{q}, '%')
    )

SELECT id AS id, comment_id AS commentId, published_at AS publishedAt, text_clean AS textClean, lex_label AS lexLabel, lex_score AS lexScore, matched AS matched, llm_label AS llmLabel, final_label AS finalLabel, CAST(corrected AS UNSIGNED) AS corrected, corrected_reason AS correctedReason FROM youtube_comment_analysis_sentiment_items WHERE history_id = #{historyId} AND (#{userId} IS NULL OR user_id = #{userId})
AND lex_label = #{label}
AND ( comment_id LIKE CONCAT('%', #{q}, '%') OR text_clean LIKE CONCAT('%', #{q}, '%') )
ORDER BY id ASC LIMIT #{limit} OFFSET #{offset}

SELECT id AS id, comment_id AS commentId, published_at AS publishedAt, text_clean AS textClean, lex_label AS lexLabel, lex_score AS lexScore, matched AS matched, llm_label AS llmLabel, final_label AS finalLabel, CAST(corrected AS UNSIGNED) AS corrected, corrected_reason AS correctedReason FROM youtube_comment_analysis_sentiment_items WHERE history_id = #{historyId} AND (#{userId} IS NULL OR user_id = #{userId}) AND id IN
#{id}
ORDER BY id ASC
